#!/usr/bin/env node
// Regenerates BruffTourData.kt and web/js/data.js from data/waypoints.yaml.
// Usage (from web/): npm run gen:waypoints

import { writeFileSync } from 'fs';
import { join } from 'path';
import { WEB_DIR, ROOT, YAML_PATH, loadWaypointsData } from './waypoints-io.js';

const KOTLIN_PATH = join(
  ROOT,
  'app',
  'src',
  'main',
  'java',
  'com',
  'example',
  'bruffwalkingtour',
  'BruffTourData.kt'
);
const JS_PATH = join(WEB_DIR, 'js', 'data.js');

const GENERATED_NOTICE =
  'edit that file and run `npm run gen:waypoints` (from web/) — do not edit this file directly.';

function kotlinString(value) {
  const escaped = String(value)
    .replace(/\\/g, '\\\\')
    .replace(/"/g, '\\"')
    .replace(/\$/g, '\\$')
    .replace(/\n+$/, '') // trailing newline from YAML block scalars
    .replace(/\n/g, '\\n');
  return `"${escaped}"`;
}

function jsString(value) {
  const trimmed = String(value).replace(/\n+$/, '');
  return JSON.stringify(trimmed);
}

function kotlinDouble(n) {
  return Number.isInteger(n) ? `${n}.0` : String(n);
}

function generateKotlin(data) {
  const { tour, waypoints } = data;

  const waypointBlocks = waypoints
    .map(
      (wp) => `                TourWaypoint(
                    id = ${kotlinString(wp.id)},
                    name = ${kotlinString(wp.name)},
                    description = ${kotlinString(wp.description)},
                    latitude = ${kotlinDouble(wp.latitude)},
                    longitude = ${kotlinDouble(wp.longitude)},
                    historicalInfo = ${kotlinString(wp.historicalInfo)},
                    proximityRadius = ${kotlinDouble(wp.proximityRadius)},
                    imageUrl = ${kotlinString(wp.imageUrl)}
                )`
    )
    .join(',\n');

  return `// AUTO-GENERATED from data/waypoints.yaml — ${GENERATED_NOTICE}
package com.example.bruffwalkingtour

object BruffTourData {

    fun getDefaultTour(): WalkingTour {
        return WalkingTour(
            id = ${kotlinString(tour.id)},
            name = ${kotlinString(tour.name)},
            description = ${kotlinString(tour.description)},
            estimatedDurationMinutes = ${tour.estimatedDurationMinutes},
            difficulty = TourDifficulty.${tour.difficulty},
            waypoints = listOf(
${waypointBlocks}
            )
        )
    }
}
`;
}

function generateJs(data) {
  const { tour, boundary, waypoints } = data;

  const waypointBlocks = waypoints
    .map(
      (wp) => `  {
    id: ${jsString(wp.id)},
    name: ${jsString(wp.name)},
    description:
      ${jsString(wp.description)},
    historicalInfo:
      ${jsString(wp.historicalInfo)},
    latitude: ${wp.latitude},
    longitude: ${wp.longitude},
    proximityRadius: ${wp.proximityRadius},
    imageUrl:
      ${jsString(wp.imageUrl)},
    localImage: ${wp.localImage ? jsString(wp.localImage) : 'null'},
  }`
    )
    .join(',\n');

  return `/**
 * AUTO-GENERATED from data/waypoints.yaml — ${GENERATED_NOTICE}
 */

/** Rectangular geo-fence centred on Sean Wall Monument. */
export const BOUNDARY = {
  CENTER_LAT: ${boundary.centerLat},
  CENTER_LON: ${boundary.centerLon},
  WIDTH_KM: ${boundary.widthKm},   // east-west
  HEIGHT_KM: ${boundary.heightKm},  // north-south
};

/** Walking speed used for ETA calculations. 83 m/min ≈ 5 km/h */
export const WALKING_SPEED_MPM = 83;

export const WAYPOINTS = [
${waypointBlocks}
];

export const TOUR = {
  id: ${jsString(tour.id)},
  name: ${jsString(tour.name)},
  description: ${jsString(tour.description)},
  estimatedDurationMinutes: ${tour.estimatedDurationMinutes},
  difficulty: ${jsString(tour.difficulty)},
};

/** Look up a waypoint by its string ID. Returns null if not found. */
export function getWaypointById(id) {
  return WAYPOINTS.find((wp) => wp.id === id) ?? null;
}

/** Returns a tour object combining metadata and waypoints. */
export function getDefaultTour() {
  return { ...TOUR, waypoints: WAYPOINTS };
}
`;
}

function main() {
  const data = loadWaypointsData();

  if (data.waypoints.length === 0) {
    throw new Error('waypoints.yaml has no waypoints');
  }

  writeFileSync(KOTLIN_PATH, generateKotlin(data), 'utf8');
  writeFileSync(JS_PATH, generateJs(data), 'utf8');

  console.log(`Generated ${KOTLIN_PATH}`);
  console.log(`Generated ${JS_PATH}`);
  console.log(`${data.waypoints.length} waypoint(s) from ${YAML_PATH}`);
}

main();
